```cpp
#include <iostream>
#include <map>
#include <iterator> // For std::next and std::prev

int main() {
    // Initialize a std::map
    std::map<int, std::string> mapExample;

    // Adding items to the map
    mapExample[1] = "one";
    mapExample[2] = "two";
    mapExample[3] = "three";

    // Access item by key and check existence before accessing to avoid adding a default-initialized element
    if (mapExample.find(2) != mapExample.end()) {
        std::cout << "Item with key 2: " << mapExample.find(2)->second << std::endl;
    }

    // Accessing the first item directly
    if (!mapExample.empty()) {
        std::pair<const int, std::string> firstItem = *(mapExample.begin());
        std::cout << "First item key: " << firstItem.first << ", value: " << firstItem.second << std::endl;
    }

    // Accessing the last item using reverse iterator
    auto lastItem = *(mapExample.rbegin()); // Using auto for brevity
    std::cout << "Last item key: " << lastItem.first << ", value: " << lastItem.second << std::endl;

    // Knowing the number of items in the map
    std::size_t itemCount = mapExample.size();
    std::cout << "Number of items in the map: " << itemCount << std::endl;

    // Access next item (Example: After the first item)
    auto it = mapExample.begin();
    auto nextItem = *(std::next(it)); // Get the second item
    std::cout << "Next item key: " << nextItem.first << ", value: " << nextItem.second << std::endl;

    // Access previous item (Example: From third to the second item)
    auto itTemp = mapExample.find(3); // Assuming key 3 exists
    if (itTemp != mapExample.begin()) { // Ensure it's not the first item
        auto prevItem = *(std::prev(itTemp));
        std::cout << "Previous item key: " << prevItem.first << ", value: " << prevItem.second << std::endl;
    }

    // Delete item by key: removing '2'
    mapExample.erase(2);

    // Delete the first item without directly using its key
    if (!mapExample.empty()) {
        mapExample.erase(mapExample.begin());
    }

    std::cout << "Items after deletions:" << std::endl;
    for (const auto& pair : mapExample) {
        std::cout << "Key: " << pair.first << ", Value: " << pair.second << std::endl;
    }

    // Note: Deleting an item by "index" (sequence) is not directly supported in std::map
    // because it is a sorted associative container, not a sequence container.

    return 0;
}
```

This example demonstrates several fundamental operations on `std::map`, including adding elements, accessing both the first and the last elements, checking the existence of an item before accessing it by key to prevent accidental insertions, iterating to next and previous elements with `std::next` and `std::prev`, knowing the total number of items with `size()`, and removing elements both by key and by iterator (for the first item). Remember, `std::map` does not support random access by index like arrays or vectors, which is why we use iterators for navigation and modifications.

