```cpp
#include <iostream>
#include <map>
#include <iterator> // Needed for std::next and std::prev

int main() {
    // Step 1: Initialize a std::map
    // 'mapExample' will store 'int' keys and 'std::string' values
    std::map<int, std::string> mapExample;

    // Step 2: Adding items
    // Direct assignment using 'operator[]' to add or modify elements
    mapExample[1] = "one";
    mapExample[2] = "two";
    mapExample[3] = "three";

    // Using 'insert' function to add new elements. It does not modify existing elements if the key exists
    mapExample.insert(std::make_pair(4, "four"));

    // Step 3: Accessing an item by key
    // Using 'find' to safely access elements prevents adding default-initialized elements if key doesn't exist
    auto findResult = mapExample.find(2); // 'find' returns an iterator to the found element or 'end' if not found
    if (findResult != mapExample.end()) {
        std::cout << "Found item with key 2: " << findResult->second << std::endl;
    } else {
        std::cout << "Key 2 not found" << std::endl;
    }

    // Step 4: Accessing the first and last items
    // 'begin()' returns an iterator to the first element; 'rbegin()' returns a reverse iterator to the last element
    if (!mapExample.empty()) { // Check if the map is not empty to avoid dereferencing end iterator
        auto firstItem = *(mapExample.begin()); // Dereference to get the first item as a pair
        auto lastItem = *(mapExample.rbegin()); // Dereference to get the last item as a pair
        std::cout << "First item: " << firstItem.first << " => " << firstItem.second << std::endl;
        std::cout << "Last item: " << lastItem.first << " => " << lastItem.second << std::endl;
    }

    // Step 5: Knowing the number of items
    // 'size()' returns the number of elements in the map
    std::size_t itemCount = mapExample.size();
    std::cout << "Number of items in the map: " << itemCount << std::endl;

    // Step 6: Iterating to next and previous items
    // Assuming we want to move from the first element, ensure the map is not empty to avoid undefined behavior
    if (!mapExample.empty()) {
        auto it = mapExample.begin();

        // Moving to next item using 'std::next'
        // Note: Check that 'it' is not at the end of the map to avoid passing the end iterator to 'std::next'
        auto nextItem = std::next(it);
        if (nextItem != mapExample.end()) {
            std::cout << "Next item: " << nextItem->first << " => " << nextItem->second << std::endl;
        }

        // Since we only have a forward iterator in std::map, we can't directly get the previous item from 'it'
        // To demonstrate accessing a previous item, first move 'it' forward
        ++it; // Move to the second item for this example
        if (it != mapExample.begin()) { // Ensure 'it' is not pointing to the first item
            auto prevItem = std::prev(it);
            std::cout << "Previous item: " << prevItem->first << " => " << prevItem->second << std::endl;
        }
    }

    // Step 7: Deleting an item
    // Deleting an item by key. This does not require moving through the map to find the key
    int keyToDelete = 2;
    mapExample.erase(keyToDelete);

    // Deleting the first item without directly using its key, using iterator from 'begin()'
    if (!mapExample.empty()) {
        mapExample.erase(mapExample.begin());
    }

    // Step 8: Display items after deletions
    std::cout << "Items after deletions:" << std::endl;
    for (const auto& [key, value] : mapExample) { // Using structured binding for readability
        std::cout << "Key: " << key << ", Value: " << value << std::endl;
    }

    // Note: std::map does not support deletion by "index" position, as it is a key-value associative container.

    return 0;
}
```

Each step in this example demonstrates a key aspect of using `std::map` in C++, from adding items to accessing and modifying the data, along with best practices like checking if the map is empty before attempting to access its elements. This provides a solid foundation for understanding and effectively using `std::map`.
